local function safeCall(func, ...)
	if type(func) ~= 'function' then return nil end
	local ok, res = pcall(func, ...)
	if not ok then warn('[Wurst UI]', res) end
	return res
end

local isfile = isfile or function(file)
	local suc, res = pcall(function() return readfile(file) end)
	return suc and res ~= nil and res ~= ''
end

local function decodeBase64(data)
	local chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
	data = tostring(data):gsub('[^'..chars..'=]', '')
	return (data:gsub('.', function(x)
		if x == '=' then return '' end
		local r, f = '', chars:find(x) - 1
		for i = 6, 1, -1 do
			r = r..(f % 2 ^ i - f % 2 ^ (i - 1) > 0 and '1' or '0')
		end
		return r
	end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
		if #x ~= 8 then return '' end
		local c = 0
		for i = 1, 8 do
			c += (x:sub(i, i) == '1' and 2 ^ (8 - i) or 0)
		end
		return string.char(c)
	end))
end

local function ensureFolder(path)
	if not makefolder then return end
	local current = ''
	for segment in tostring(path):gmatch('[^/]+') do
		if segment:find('%.') then break end
		current = current == '' and segment or (current..'/'..segment)
		if not isfolder or not isfolder(current) then
			pcall(makefolder, current)
		end
	end
end

local function ensureEmbeddedAsset(path, data)
	if data == '' or not writefile then return end
	if isfile(path) then return end
	ensureFolder(path)
	pcall(function()
		writefile(path, decodeBase64(data))
	end)
end

local function loadJson(path)
	if not isfile(path) then return nil end
	local suc, res = pcall(function()
		return httpService:JSONDecode(readfile(path))
	end)
	return suc and type(res) == 'table' and res or nil
end

local function saveJson(path, data)
	if not writefile then return end
	ensureFolder(path)
	pcall(function()
		writefile(path, httpService:JSONEncode(data))
	end)
end

local function getfontsize(text, size, font)
	fontsize.Text = text or ''
	fontsize.Size = size or 11
	if typeof(font) == 'Font' then fontsize.Font = font end
	return textService:GetTextBoundsAsync(fontsize)
end

local function randomString()
	local array = {}
	for i = 1, math.random(10, 100) do
		array[i] = string.char(math.random(32, 126))
	end
	return table.concat(array)
end

