local function stroke(obj, thickness, transparency, col)
	local s = Instance.new('UIStroke')
	s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	s.Color = col or uipallet.Border
	s.Thickness = thickness or 1
	s.Transparency = transparency or 0
	s.Parent = obj
	return s
end

local function makeText(parent, txt, size, bold)
	local label = Instance.new('TextLabel')
	label.BackgroundTransparency = 1
	label.Text = txt or ''
	label.TextColor3 = uipallet.Text
	label.TextSize = size or 11
	label.FontFace = bold and uipallet.FontSemiBold or uipallet.Font
	label.TextXAlignment = Enum.TextXAlignment.Left
	label.TextYAlignment = Enum.TextYAlignment.Center
	label.Parent = parent
	return label
end

local function makeShadowedText(parent, txt, size, pos, textCol)
	local shadow = makeText(parent, txt, size, true)
	shadow.Position = pos + UDim2.fromOffset(1, 1)
	shadow.Size = UDim2.new(1, 0, 0, size + 4)
	shadow.TextColor3 = Color3.new()
	local label = makeText(parent, txt, size, true)
	label.Position = pos
	label.Size = UDim2.new(1, 0, 0, size + 4)
	label.TextColor3 = textCol or uipallet.Text
	return label
end

local function canonicalCategoryName(name)
	name = tostring(name or 'Other')
	if CATEGORY_ALIASES[name] then return CATEGORY_ALIASES[name] end
	if table.find(WURST_ORDER, name) then return name end

	local lowered = name:lower()
	if lowered:find('block') or lowered:find('world') or lowered:find('place') or lowered:find('build') then return 'Blocks' end
	if lowered:find('move') or lowered:find('speed') or lowered:find('fly') or lowered:find('jump') or lowered:find('motion') or lowered:find('player') then return 'Movement' end
	if lowered:find('combat') or lowered:find('fight') or lowered:find('aura') or lowered:find('attack') or lowered:find('weapon') or lowered:find('hit') then return 'Combat' end
	if lowered:find('render') or lowered:find('visual') or lowered:find('esp') or lowered:find('overlay') or lowered:find('nametag') then return 'Render' end
	if lowered:find('chat') or lowered:find('message') or lowered:find('say') then return 'Chat' end
	if lowered:find('fun') or lowered:find('troll') or lowered:find('cosmetic') or lowered:find('mini') then return 'Fun' end
	if lowered:find('item') or lowered:find('inv') or lowered:find('tool') or lowered:find('loot') then return 'Items' end

	return 'Other'
end

local function moduleKey(categoryName, name)
	return canonicalCategoryName(categoryName)..':'..tostring(name or ''):gsub('%s+', ''):lower()
end

local MODULE_CATEGORY_HINTS = {
	Blocks = {'scaffold', 'bed', 'block', 'chest', 'bridge', 'place', 'break', 'mlg'},
	Movement = {'speed', 'fly', 'flight', 'jump', 'highjump', 'sprint', 'noclip', 'blink', 'parkour', 'velocity', 'desync'},
	Combat = {'aim', 'aura', 'hitbox', 'reach', 'trap', 'm2tap', 'kick', 'delay', 'stamina', 'dive', 'physical', 'allhbe', 'autotrap', 'nodelay', 'nokick', 'customkick', 'fakelag'},
	Render = {'esp', 'visual', 'render', 'tracksuit', 'disguise', 'offsides', 'positions', 'backtrack', 'staff'},
	Chat = {'chat', 'say', 'translator', 'message', 'spam'},
	Fun = {'panic', 'troll', 'prop', 'murderer', 'fish', 'rejoin'},
	Items = {'item', 'tool', 'inventory', 'chest', 'steal', 'autoitem'}
}

local function categoryFromModuleName(defaultCategory, moduleName)
	local lower = tostring(moduleName or ''):lower()
	for categoryName, words in pairs(MODULE_CATEGORY_HINTS) do
		for _, word in ipairs(words) do
			if lower:find(word, 1, true) then
				return categoryName
			end
		end
	end
	return canonicalCategoryName(defaultCategory)
end


local function safeText(value)
	if type(value) == 'function' then
		local ok, res = pcall(value, 0)
		return ok and tostring(res) or ''
	end
	return tostring(value or '')
end

local function safeSuffix(suffix, value)
	if type(suffix) == 'function' then
		local ok, res = pcall(suffix, value)
		return ok and tostring(res or '') or ''
	end
	return tostring(suffix or '')
end



local function bringToFront(windowapi)
	focusedZ += 1
	windowapi.Frame.ZIndex = focusedZ
	for _, child in ipairs(windowapi.Frame:GetDescendants()) do
		if child:IsA('GuiObject') then
			child.ZIndex = focusedZ
		end
	end
end

local function saveWindows()
	local data = {Windows = {}, Settings = mainapi.Settings}
	for name, windowapi in pairs(mainapi.Windows) do
		data.Windows[name] = {
			X = windowapi.X,
			Y = windowapi.Y,
			Minimized = windowapi.Minimized,
			Pinned = windowapi.Pinned,
			Closed = windowapi.Closed
		}
	end
	saveJson('newvape/profiles/wurst_windows.json', data)
	saveJson('newvape/profiles/wurst_settings.json', mainapi.Settings)
end

local savedWindows = loadJson('newvape/profiles/wurst_windows.json') or {Windows = {}}

local function updateAutoScale()
	if not scale or not gui or not scaledgui then return end
	if mainapi.Settings.AutoScale == false then
		scale.Scale = mainapi.Scale.Value or 1
	else
		local size = gui.AbsoluteSize
		local sx = size.X > 0 and (size.X / 1040) or 1
		local sy = size.Y > 0 and (size.Y / 650) or 1
		scale.Scale = math.clamp(math.min(sx, sy), 1.15, 1.75)
	end
	scaledgui.Size = UDim2.fromScale(1 / scale.Scale, 1 / scale.Scale)
end

local function windowShouldShow(windowapi)
	if windowapi.Closed then return false end
	if clickgui and clickgui.Visible then return true end
	return windowapi.Pinned == true
end

local function updateWindowVisibility()
	for _, windowapi in pairs(mainapi.Windows) do
		windowapi.Frame.Visible = windowShouldShow(windowapi)
	end

	if logoFrame then
		local showLogo = mainapi.Settings.WurstLogo ~= false
		local showHackList = mainapi.Settings.HackList ~= false
		logoFrame.Visible = showLogo or showHackList

		if logoImage then logoImage.Visible = showLogo and logoImage.Image ~= '' end
		if versionLabel then versionLabel.Visible = showLogo end
		if activeList then activeList.Visible = showHackList end
	end
end

local function setTooltip(text)
	if not tooltip or not tooltipText then return end
	if not text or text == '' then
		tooltip.Visible = false
		return
	end

	tooltipText.Text = tostring(text)
	local bounds = getfontsize(tooltipText.Text, 11, uipallet.Font)
	tooltip.Size = UDim2.fromOffset(math.min(bounds.X + 10, 320), bounds.Y + 8)
	tooltip.BackgroundTransparency = 1 - math.clamp(mainapi.Settings.TooltipOpacity or 0.75, 0, 1)
	tooltip.Visible = true
end

local function connectTooltip(obj, text)
	obj.MouseEnter:Connect(function()
		setTooltip(text)
	end)
	obj.MouseLeave:Connect(function()
		setTooltip(nil)
	end)
end

local function updateTooltipPosition()
	if not tooltip or not tooltip.Visible then return end
	local mouse = inputService:GetMouseLocation()
	local x = mouse.X / scale.Scale + 12
	local y = (mouse.Y + guiService:GetGuiInset().Y) / scale.Scale + 12
	local size = gui.AbsoluteSize / scale.Scale
	if x + tooltip.AbsoluteSize.X > size.X then
		x = x - tooltip.AbsoluteSize.X - 24
	end
	if y + tooltip.AbsoluteSize.Y > size.Y then
		y = y - tooltip.AbsoluteSize.Y - 24
	end
	tooltip.Position = UDim2.fromOffset(math.max(x, 0), math.max(y, 0))
end

local function closePopup()
	if currentPopup then
		currentPopup:Destroy()
		currentPopup = nil
	end
end

local function createWindow(name, title, width, height, closable)
	local windowapi = {
		Name = name,
		Title = title,
		X = 8,
		Y = 8,
		Minimized = false,
		Pinned = false,
		Closed = false,
		Closable = closable == true
	}
	local saved = savedWindows.Windows and savedWindows.Windows[name]
	if saved then
		windowapi.X = saved.X or windowapi.X
		windowapi.Y = saved.Y or windowapi.Y
		windowapi.Minimized = saved.Minimized == true
		windowapi.Pinned = saved.Pinned == true
		windowapi.Closed = saved.Closed == true and closable == true
	end

	local frame = Instance.new('Frame')
	frame.Name = name
	frame.Size = UDim2.fromOffset(width, height)
	frame.Position = UDim2.fromOffset(windowapi.X, windowapi.Y)
	frame.BackgroundColor3 = uipallet.Main
	frame.BackgroundTransparency = 1 - math.clamp(mainapi.Settings.Opacity or 0.82, 0, 1)
	frame.BorderSizePixel = 0
	frame.Visible = false
	frame.Parent = scaledgui
	stroke(frame, 1, 0.05)

	local header = Instance.new('TextButton')
	header.Name = 'TitleBar'
	header.Size = UDim2.new(1, 0, 0, 13)
	header.BackgroundColor3 = uipallet.Header
	header.BackgroundTransparency = uipallet.HeaderAlpha
	header.BorderSizePixel = 0
	header.Text = ''
	header.AutoButtonColor = false
	header.Parent = frame
	stroke(header, 1, 0.45)

	local titleText = makeText(header, title, 10, true)
	titleText.Size = UDim2.new(1, closable and -37 or -25, 1, 0)
	titleText.Position = UDim2.fromOffset(3, 0)

	local pin = Instance.new('TextButton')
	pin.Name = 'Pin'
	pin.Size = UDim2.fromOffset(8, 8)
	pin.Position = UDim2.new(1, closable and -28 or -18, 0, 2)
	pin.Text = ''
	pin.AutoButtonColor = false
	pin.BackgroundColor3 = windowapi.Pinned and uipallet.Enabled or Color3.fromRGB(150, 35, 35)
	pin.BorderSizePixel = 0
	pin.Parent = header
	stroke(pin, 1, 0.1)
	connectTooltip(pin, 'Pin window')

	local minimize = Instance.new('TextButton')
	minimize.Name = 'Minimize'
	minimize.Size = UDim2.fromOffset(8, 8)
	minimize.Position = UDim2.new(1, closable and -18 or -9, 0, 2)
	minimize.Text = ''
	minimize.AutoButtonColor = false
	minimize.BackgroundColor3 = Color3.fromRGB(34, 150, 45)
	minimize.BorderSizePixel = 0
	minimize.Parent = header
	stroke(minimize, 1, 0.1)
	connectTooltip(minimize, 'Minimize window')

	local close
	if closable then
		close = Instance.new('TextButton')
		close.Name = 'Close'
		close.Size = UDim2.fromOffset(8, 8)
		close.Position = UDim2.new(1, -9, 0, 2)
		close.Text = '×'
		close.TextSize = 9
		close.TextColor3 = Color3.new()
		close.AutoButtonColor = false
		close.BackgroundColor3 = Color3.fromRGB(170, 45, 45)
		close.BorderSizePixel = 0
		close.Parent = header
		stroke(close, 1, 0.1)
		connectTooltip(close, 'Close window')
	end

	local body = Instance.new('ScrollingFrame')
	body.Name = 'Body'
	body.Position = UDim2.fromOffset(0, 13)
	body.Size = UDim2.new(1, 0, 1, -13)
	body.BackgroundTransparency = 1
	body.BorderSizePixel = 0
	body.ScrollBarThickness = 2
	body.ScrollBarImageColor3 = Color3.fromRGB(15, 15, 15)
	body.ScrollBarImageTransparency = 0.25
	body.CanvasSize = UDim2.new()
	body.Visible = not windowapi.Minimized
	body.Parent = frame

	local layout = Instance.new('UIListLayout')
	layout.SortOrder = Enum.SortOrder.LayoutOrder
	layout.Padding = UDim.new(0, 1)
	layout.Parent = body

	windowapi.Frame = frame
	windowapi.Header = header
	windowapi.Body = body
	windowapi.Layout = layout
	windowapi.TitleText = titleText
	windowapi.PinButton = pin
	windowapi.MinimizeButton = minimize
	windowapi.CloseButton = close

	local function applySize()
		local bodyHeight = layout.AbsoluteContentSize.Y
		local maxHeight = name:find('Settings') and (mainapi.Settings.MaxSettingsHeight or 320) or (mainapi.Settings.MaxWindowHeight or 240)
		local h = windowapi.Minimized and 13 or math.clamp(13 + bodyHeight + 2, 13, maxHeight)
		frame.Size = UDim2.fromOffset(width, h)
		body.Visible = not windowapi.Minimized
		body.Size = UDim2.new(1, 0, 1, -13)
		body.CanvasSize = UDim2.fromOffset(0, bodyHeight + 2)
	end

	function windowapi:Apply()
		self.PinButton.BackgroundColor3 = self.Pinned and uipallet.Enabled or Color3.fromRGB(150, 35, 35)
		self.Body.Visible = not self.Minimized
		self.Frame.Position = UDim2.fromOffset(self.X, self.Y)
		applySize()
		updateWindowVisibility()
	end

	function windowapi:SetPinned(state)
		self.Pinned = state == true
		self:Apply()
		saveWindows()
	end

	function windowapi:SetMinimized(state)
		self.Minimized = state == true
		self:Apply()
		saveWindows()
	end

	function windowapi:Close()
		self.Closed = true
		self:Apply()
		saveWindows()
	end

	layout:GetPropertyChangedSignal('AbsoluteContentSize'):Connect(applySize)

	local dragging, dragOffset
	header.InputBegan:Connect(function(inputObj)
		bringToFront(windowapi)
		if inputObj.UserInputType == Enum.UserInputType.MouseButton1 or inputObj.UserInputType == Enum.UserInputType.Touch then
			dragging = true
			local pos = inputObj.Position
			dragOffset = Vector2.new(windowapi.X - (pos.X / scale.Scale), windowapi.Y - ((pos.Y + guiService:GetGuiInset().Y) / scale.Scale))
		end
	end)
	inputService.InputChanged:Connect(function(inputObj)
		if dragging and (inputObj.UserInputType == Enum.UserInputType.MouseMovement or inputObj.UserInputType == Enum.UserInputType.Touch) then
			local pos = inputObj.Position
			local screen = gui.AbsoluteSize / scale.Scale
			windowapi.X = math.clamp((pos.X / scale.Scale) + dragOffset.X, -width + 30, math.max(screen.X - 20, 20))
			windowapi.Y = math.clamp(((pos.Y + guiService:GetGuiInset().Y) / scale.Scale) + dragOffset.Y, 0, math.max(screen.Y - 13, 13))
			frame.Position = UDim2.fromOffset(windowapi.X, windowapi.Y)
		end
	end)
	inputService.InputEnded:Connect(function(inputObj)
		if inputObj.UserInputType == Enum.UserInputType.MouseButton1 or inputObj.UserInputType == Enum.UserInputType.Touch then
			if dragging then saveWindows() end
			dragging = false
		end
	end)

	header.MouseButton2Click:Connect(function()
		windowapi:SetMinimized(not windowapi.Minimized)
	end)
	pin.MouseButton1Click:Connect(function()
		windowapi:SetPinned(not windowapi.Pinned)
	end)
	minimize.MouseButton1Click:Connect(function()
		windowapi:SetMinimized(not windowapi.Minimized)
	end)
	if close then
		close.MouseButton1Click:Connect(function()
			windowapi:Close()
		end)
	end
	frame.InputBegan:Connect(function()
		bringToFront(windowapi)
	end)

	mainapi.Windows[name] = windowapi
	applySize()
	return windowapi
end

local components = {}

local function createOptionBase(kind, optionsettings, parent, moduleapi)
	optionsettings = optionsettings or {}
	if not parent then
		local optionapi = {
			Type = kind,
			Name = optionsettings.Name or kind,
			Default = optionsettings.Default,
			Value = optionsettings.Default,
			Function = optionsettings.Function or function() end,
			Object = nil
		}
		function optionapi:SetValue(val, _, final)
			self.Value = val
			safeCall(self.Function, val, final)
			return self
		end
		function optionapi:Reset()
			return self:SetValue(self.Default, nil, true)
		end
		function optionapi:SetVisible() return self end
		function optionapi:Save(tab) if type(tab) == 'table' then tab[self.Name] = {Value = self.Value} end end
		function optionapi:Load(tab) if type(tab) == 'table' and tab.Value ~= nil then self:SetValue(tab.Value) end end
		if moduleapi and moduleapi.Options then table.insert(moduleapi.Options, optionapi) end
		return optionapi
	end
	local optionapi = {
		Type = kind,
		Name = optionsettings.Name or kind,
		Default = optionsettings.Default,
		Value = optionsettings.Default,
		Function = optionsettings.Function or function() end,
		Object = nil,
		Tooltip = optionsettings.Tooltip or optionsettings.HoverText or optionsettings.Description,
		Visible = optionsettings.Visible ~= false
	}
	local row = Instance.new('TextButton')
	row.Name = optionapi.Name
	row.Size = UDim2.new(1, -6, 0, 14)
	row.BackgroundColor3 = Color3.fromRGB(72, 78, 93)
	row.BackgroundTransparency = 0.38
	row.BorderSizePixel = 0
	row.AutoButtonColor = false
	row.Text = ''
	row.Visible = optionapi.Visible
	row.Parent = parent
	stroke(row, 1, 0.35)
	local label = makeText(row, optionapi.Name, 11, false)
	label.Size = UDim2.new(1, -8, 1, 0)
	label.Position = UDim2.fromOffset(3, 0)
	optionapi.Object = row
	optionapi.Label = label
	if optionapi.Tooltip then connectTooltip(row, optionapi.Tooltip) end

	function optionapi:SetValue(val, _, final)
		self.Value = val
		safeCall(self.Function, val, final)
	end
	function optionapi:SetVisible(state)
		self.Visible = state == true
		if self.Object then self.Object.Visible = self.Visible end
	end
	function optionapi:Toggle()
		self:SetValue(not self.Value, nil, true)
	end
	function optionapi:Reset()
		self:SetValue(self.Default, nil, true)
	end

	setmetatable(optionapi, {
		__index = function(tab, ind)
			if tostring(ind):sub(1, 3) == 'Set' then
				return function(_, val)
					tab.Value = val
					if ind == 'SetVisible' then tab:SetVisible(val) end
					return tab
				end
			end
			return function() return tab end
		end
	})

	table.insert(moduleapi.Options, optionapi)
	return optionapi
end

