components.Slider = function(optionsettings, parent, moduleapi)
	local api = createOptionBase('Slider', optionsettings, parent, moduleapi)
	api.Min = optionsettings.Min or 0
	api.Max = optionsettings.Max or 100
	api.Decimal = optionsettings.Decimal or 1
	api.Default = optionsettings.Default or api.Min
	api.Value = api.Default
	api.Suffix = optionsettings.Suffix or ''
	local value = makeText(api.Object, tostring(api.Value)..safeSuffix(api.Suffix, api.Value), 10, false)
	value.Size = UDim2.new(0, 38, 1, 0)
	value.Position = UDim2.new(1, -40, 0, 0)
	value.TextXAlignment = Enum.TextXAlignment.Right
	local bar = Instance.new('Frame')
	bar.Size = UDim2.new(1, -8, 0, 2)
	bar.Position = UDim2.new(0, 4, 1, -3)
	bar.BorderSizePixel = 0
	bar.BackgroundColor3 = Color3.fromRGB(38, 42, 52)
	bar.Parent = api.Object
	local fill = Instance.new('Frame')
	fill.BorderSizePixel = 0
	fill.BackgroundColor3 = uipallet.Slider
	fill.Parent = bar

	local function update()
		local pct = math.clamp((api.Value - api.Min) / math.max(api.Max - api.Min, 1), 0, 1)
		fill.Size = UDim2.new(pct, 0, 1, 0)
		value.Text = tostring(math.floor(api.Value * 100) / 100)..safeSuffix(api.Suffix, api.Value)
	end

	function api:SetValue(val, _, final)
		val = math.clamp(tonumber(val) or api.Min, api.Min, api.Max)
		if api.Decimal and api.Decimal > 1 then
			val = math.floor(val * api.Decimal + 0.5) / api.Decimal
		elseif api.Decimal and api.Decimal > 0 and api.Decimal < 1 then
			val = math.floor(val / api.Decimal + 0.5) * api.Decimal
		end
		self.Value = val
		update()
		safeCall(self.Function, val, final)
	end

	local dragging = false
	local function setFromX(x, final)
		local pct = math.clamp((x - bar.AbsolutePosition.X) / math.max(bar.AbsoluteSize.X, 1), 0, 1)
		api:SetValue(api.Min + (api.Max - api.Min) * pct, nil, final)
	end

	api.Object.MouseButton1Down:Connect(function()
		if inputService:IsKeyDown(Enum.KeyCode.LeftControl) or inputService:IsKeyDown(Enum.KeyCode.RightControl) then
			local box = Instance.new('TextBox')
			box.Size = UDim2.fromOffset(56, 14)
			box.Position = value.Position
			box.BackgroundColor3 = Color3.fromRGB(30, 33, 40)
			box.BorderSizePixel = 0
			box.Text = tostring(api.Value)
			box.TextColor3 = uipallet.Text
			box.TextSize = 10
			box.FontFace = uipallet.Font
			box.ClearTextOnFocus = false
			box.Parent = api.Object
			stroke(box, 1, 0.1)
			box:CaptureFocus()
			box.FocusLost:Connect(function()
				api:SetValue(tonumber(box.Text) or api.Value, nil, true)
				box:Destroy()
			end)
			return
		end
		dragging = true
		setFromX(inputService:GetMouseLocation().X, false)
	end)

	api.Object.MouseButton2Click:Connect(function() api:Reset() end)
	mainapi:Clean(inputService.InputChanged:Connect(function(inputObj)
		if dragging and inputObj.UserInputType == Enum.UserInputType.MouseMovement then setFromX(inputObj.Position.X, false) end
	end))
	mainapi:Clean(inputService.InputEnded:Connect(function(inputObj)
		if inputObj.UserInputType == Enum.UserInputType.MouseButton1 and dragging then
			dragging = false
			safeCall(api.Function, api.Value, true)
		end
	end))
	update()
	return api
end
