local function createDropdownPopup(api, valueLabel)
	closePopup()
	local popup = Instance.new('Frame')
	popup.Name = 'ComboBoxPopup'
	popup.BackgroundColor3 = uipallet.Main
	popup.BackgroundTransparency = 0.38
	popup.BorderSizePixel = 0
	popup.ZIndex = 9999
	popup.Parent = scaledgui
	stroke(popup, 1, 0.05)
	currentPopup = popup

	local abs = api.Object.AbsolutePosition / scale.Scale
	popup.Position = UDim2.fromOffset(abs.X, abs.Y + api.Object.AbsoluteSize.Y / scale.Scale)
	popup.Size = UDim2.fromOffset(api.Object.AbsoluteSize.X / scale.Scale, math.min(#api.List * 14, 140))

	local list = Instance.new('UIListLayout')
	list.Parent = popup

	for _, item in ipairs(api.List) do
		local row = Instance.new('TextButton')
		row.Size = UDim2.new(1, 0, 0, 14)
		row.BackgroundColor3 = item == api.Value and uipallet.Enabled or uipallet.Main
		row.BackgroundTransparency = item == api.Value and 0 or 0.05
		row.BorderSizePixel = 0
		row.AutoButtonColor = false
		row.Text = tostring(item)
		row.TextColor3 = item == api.Value and uipallet.DarkText or uipallet.Text
		row.TextSize = 10
		row.FontFace = uipallet.Font
		row.ZIndex = 10000
		row.Parent = popup
		row.MouseButton1Click:Connect(function()
			api:SetValue(item, nil, true)
			valueLabel.Text = tostring(item)
			closePopup()
		end)
	end
end

