mainapi.Components = setmetatable(components, {
	__newindex = function(self, ind, func)
		for _, v in pairs(mainapi.Modules) do
			if type(v) == 'table' then
				rawset(v, 'Create'..ind, function(_, settings)
					return func(settings or {}, v.SettingsList or v.Children, v)
				end)
			end
		end
		rawset(self, ind, func)
	end
})

setmetatable(mainapi, {
	__index = function(tab, ind)
		if type(ind) == 'string' then
			if ind:find('GUI', 1, true) or ind:find('bind', 1, true) or ind:find('Indicator', 1, true) or ind:find('indicator', 1, true) then
				local stub = {
					Enabled = false,
					Object = nil,
					SetValue = function(self, val) self.Enabled = val == true return self end,
					Toggle = function(self) self.Enabled = not self.Enabled return self end,
					Clean = function() end,
					Save = function() end,
					Load = function() end
				}
				rawset(tab, ind, stub)
				return stub
			end
		end
		return nil
	end
})

function mainapi:Clean(obj)
	if typeof(obj) == 'Instance' then
		table.insert(self.Connections, {Disconnect = function()
			if obj then pcall(function() obj:ClearAllChildren(); obj:Destroy() end) end
		end})
		return
	end
	if typeof(obj) == 'RBXScriptConnection' then
		table.insert(self.Connections, obj)
		return
	end
	if type(obj) == 'function' then
		table.insert(self.Connections, {Disconnect = obj})
		return
	end
	if type(obj) == 'table' and type(obj.Disconnect) == 'function' then
		table.insert(self.Connections, obj)
	end
end

function mainapi:UpdateTextGUI()
	if not activeList then return end
	local enabled = {}
	for _, moduleapi in ipairs(self.ModuleList) do
		if moduleapi.Enabled then table.insert(enabled, moduleapi.Name) end
	end
	table.sort(enabled)
	activeList.Text = table.concat(enabled, '\n')
	updateWindowVisibility()
end

function mainapi:UpdateGUI() end
function mainapi:UpdateTextGUI()
	if activeList then
		local enabled = {}
		for _, moduleapi in ipairs(self.ModuleList or {}) do
			if moduleapi.Enabled then table.insert(enabled, moduleapi.Name) end
		end
		table.sort(enabled)
		activeList.Text = table.concat(enabled, '\n')
	end
	if updateWindowVisibility then updateWindowVisibility() end
end
function mainapi:Update()
	self:UpdateGUI()
	self:UpdateTextGUI()
end
function mainapi:Refresh()
	self:Update()
end
function mainapi:Load()
	self.Loaded = true
end
function mainapi:Save()
	saveWindows()
end
