	warn('[Wurst UI Notification]', text or '')
end
function mainapi:Uninject(silent)
	if self.Uninjecting then return end
	self.Uninjecting = true

	pcall(function()
		self:Save()
	end)

	for _, moduleapi in ipairs(self.ModuleList or {}) do
		pcall(function()
			if moduleapi.Enabled and moduleapi.Toggle then
				moduleapi:Toggle(true)
			end
		end)

		if moduleapi.Connections then
			for _, connection in ipairs(moduleapi.Connections) do
				pcall(function()
					if typeof(connection) == 'RBXScriptConnection' then
						connection:Disconnect()
					elseif type(connection) == 'function' then
						connection()
					elseif type(connection) == 'table' and connection.Disconnect then
						connection:Disconnect()
					end
				end)
			end
			table.clear(moduleapi.Connections)
		end
	end

	for _, connection in ipairs(self.Connections or {}) do
		pcall(function()
			if typeof(connection) == 'RBXScriptConnection' then
				connection:Disconnect()
			elseif type(connection) == 'function' then
				connection()
			elseif type(connection) == 'table' and connection.Disconnect then
				connection:Disconnect()
			end
		end)
	end
	table.clear(self.Connections)

	pcall(function()
		if self.gui then
			self.gui:ClearAllChildren()
			self.gui:Destroy()
		end
	end)

	pcall(function()
		if shared and rawget(shared, 'vape') == self then
			shared.vape = nil
		end
	end)

	self.Loaded = nil
	if not silent then
		warn('[Wurst UI] Uninjected')
	end
end

local function ensureOptionApi(optionapi)
	if type(optionapi) ~= 'table' then return optionapi end
	optionapi.Name = optionapi.Name or optionapi.Type or 'Option'
	optionapi.Type = optionapi.Type or 'Unknown'
	optionapi.Default = optionapi.Default == nil and optionapi.Value or optionapi.Default

	optionapi.SetValue = optionapi.SetValue or function(self, val)
		self.Value = val
		return self
	end
	optionapi.Update = optionapi.Update or function(self, val)
		if val ~= nil then
			self:SetValue(val)
		end
		return self
	end
	optionapi.Reset = optionapi.Reset or function(self)
		self:SetValue(self.Default)
		return self
	end
	optionapi.SetVisible = optionapi.SetVisible or function(self, state)
		if self.Object then self.Object.Visible = state == true end
		return self
	end
	optionapi.Save = optionapi.Save or function(self, tab)
		if type(tab) == 'table' then
			tab[self.Name] = {Value = self.Value}
		end
	end
	optionapi.Load = optionapi.Load or function(self, tab)
		if type(tab) == 'table' and tab.Value ~= nil then
			self:SetValue(tab.Value)
		end
	end

	return optionapi
end

local function safeCreateOption(compName, moduleapi, optionsettings)
	optionsettings = optionsettings or {}
	local parent = moduleapi.SettingsList or moduleapi.Children or (moduleapi.SettingsWindow and moduleapi.SettingsWindow.Body)
	local maker = components[compName]

	if maker then
		local ok, res = pcall(maker, optionsettings, parent, moduleapi)
		if ok and type(res) == 'table' then
			return ensureOptionApi(res)
		end
		warn('[Wurst UI] option failed for '..tostring(moduleapi.Name)..' / '..tostring(compName)..': '..tostring(res))
	end

	return ensureOptionApi(createOptionBase(compName, optionsettings, parent, moduleapi))
end

local function ensureModuleApi(moduleapi)
	if type(moduleapi) ~= 'table' then return moduleapi end

	moduleapi.Options = moduleapi.Options or {}
	moduleapi.Connections = moduleapi.Connections or {}
	moduleapi.Bind = moduleapi.Bind or ''
	moduleapi.Enabled = moduleapi.Enabled == true
	moduleapi.Tooltip = moduleapi.Tooltip or moduleapi.HoverText or moduleapi.Description

	moduleapi.Clean = moduleapi.Clean or function(self, obj)
		if typeof(obj) == 'Instance' then
			table.insert(self.Connections, {Disconnect = function()
				if obj then pcall(function() obj:ClearAllChildren(); obj:Destroy() end) end
			end})
		elseif typeof(obj) == 'RBXScriptConnection' then
			table.insert(self.Connections, obj)
		elseif type(obj) == 'thread' then
			table.insert(self.Connections, {Disconnect = function() pcall(task.cancel, obj) end})
		elseif type(obj) == 'function' then
			table.insert(self.Connections, {Disconnect = obj})
		elseif type(obj) == 'table' and obj.Disconnect then
			table.insert(self.Connections, obj)
		end
	end

	moduleapi.SetBind = moduleapi.SetBind or function(self, val)
		if type(val) == 'table' then
			self.Bind = val[1] or ''
		else
			self.Bind = val or ''
		end
		return self
	end

	moduleapi.SetVisible = moduleapi.SetVisible or function(self, state)
		if self.Object then self.Object.Visible = state == true end
		return self
	end

	moduleapi.SetExtraText = moduleapi.SetExtraText or function(self, txt)
		self.ExtraText = txt
		return self
	end

	moduleapi.Update = moduleapi.Update or function(self)
		if mainapi and mainapi.UpdateTextGUI then
			mainapi:UpdateTextGUI()
		end
		return self
	end

	for compName in pairs(components) do
		local method = 'Create'..compName
		if moduleapi[method] == nil then
			moduleapi[method] = function(self, optionsettings)
				return safeCreateOption(compName, self, optionsettings)
			end
		end
	end

	local aliasMap = {
		CreateTextBox = 'Textbox',
		CreateTextbox = 'Textbox',
		CreateTextField = 'Textbox',
		CreateInput = 'Textbox',
		CreateSlider = 'Slider',
		CreateToggle = 'Toggle',
		CreateDropdown = 'Dropdown',
		CreateColorSlider = 'ColorSlider',
		CreateColor = 'ColorSlider',
		CreateButton = 'Button',
		CreateKeybind = 'Keybind',
		CreateBind = 'Keybind',
		CreateMultiDropdown = 'Dropdown',
		CreateRangeSlider = 'Slider',
		CreateTextList = 'Textbox',
		CreateList = 'Textbox'
	}

	for method, compName in pairs(aliasMap) do
		moduleapi[method] = moduleapi[method] or function(self, optionsettings)
			return safeCreateOption(compName, self, optionsettings)
		end
	end

	return moduleapi
end

function mainapi:CreateCategory(categorysettings)
	categorysettings = categorysettings or {}
	local original = categorysettings.Name or 'Other'
	local canonical = canonicalCategoryName(original)

	local existing = rawget(self.Categories, canonical)
	if existing then
		rawset(self.Categories, original, existing)
		return existing
	end

	local categoryapi = {Type = 'Category', Name = canonical, OriginalName = original, Modules = {}}
	local window = createWindow(canonical..'Window', canonical, 92, 30, false)
	window.Frame.Name = canonical..'Window'
	categoryapi.WindowAPI = window
	categoryapi.Window = window.Frame
	categoryapi.Header = window.Header
	categoryapi.Children = window.Body
	categoryapi.Layout = window.Layout
	categoryapi.Minimized = window.Minimized

	function categoryapi:SetMinimized(state)
		self.WindowAPI:SetMinimized(state)
	end

	function categoryapi:CreateModule(modulesettings)
		modulesettings = modulesettings or {}
		local name = tostring(modulesettings.Name or ('Module'..tostring(#self.Modules + 1)))
		local finalCategory = categoryFromModuleName(canonical, name)
		local ownerCategory = finalCategory ~= canonical and mainapi.Categories[finalCategory] or self
		if ownerCategory and ownerCategory ~= self then
			return ownerCategory:CreateModule(modulesettings)
		end
		local key = moduleKey(canonical, name)
		if mainapi.ModuleKeys[key] then
			local existing = mainapi.Modules[mainapi.ModuleKeys[key]]
			if existing and existing.Object and existing.Object.Parent then
				existing.Function = modulesettings.Function or existing.Function
				existing.Tooltip = modulesettings.Tooltip or modulesettings.HoverText or modulesettings.Description or existing.Tooltip
				return ensureModuleApi(existing)
			end
			mainapi.ModuleKeys[key] = nil
		end

		local moduleapi = {
			Enabled = false,
			Options = {},
			Bind = '',
			Connections = {},
			Index = modulesettings.Index or (#self.Modules + 1),
			ExtraText = modulesettings.ExtraText,
			Name = name,
			Category = canonical,
			Function = modulesettings.Function or function() end,
			Tooltip = modulesettings.Tooltip or modulesettings.HoverText or modulesettings.Description,
			SettingsList = nil
		}

		local row = Instance.new('TextButton')
		row.Name = name
		row.Size = UDim2.new(1, 0, 0, 11)
		row.BackgroundColor3 = uipallet.Main
		row.BackgroundTransparency = uipallet.MainAlpha
		row.BorderSizePixel = 0
		row.AutoButtonColor = false
		row.Text = ''
		row.Parent = window.Body
		stroke(row, 1, 0.48)

		local text = makeText(row, name, 9, false)
		text.Size = UDim2.new(1, -15, 1, 0)
		text.Position = UDim2.fromOffset(2, 0)
		text.TextXAlignment = Enum.TextXAlignment.Center

		local settingsStrip = Instance.new('TextButton')
		settingsStrip.Size = UDim2.fromOffset(11, 11)
		settingsStrip.Position = UDim2.new(1, -11, 0, 0)
		settingsStrip.BackgroundColor3 = uipallet.Main
		settingsStrip.BackgroundTransparency = uipallet.MainAlpha
		settingsStrip.BorderSizePixel = 0
		settingsStrip.Text = '▾'
		settingsStrip.TextSize = 9
		settingsStrip.TextColor3 = uipallet.Enabled
		settingsStrip.FontFace = uipallet.FontSemiBold
		settingsStrip.Parent = row
		stroke(settingsStrip, 1, 0.48)

		local settingsWindow = createWindow('Settings_'..canonical..'_'..name, name, 148, 50, true)
		settingsWindow.Frame.Visible = false
		moduleapi.SettingsWindow = settingsWindow
		moduleapi.SettingsList = settingsWindow.Body
		moduleapi.Children = settingsWindow.Body
		settingsWindow.Closed = true

		local desc = makeText(settingsWindow.Body, 'Type: Module\nCategory: '..canonical..'\n'..(moduleapi.Tooltip or 'No description'), 10, false)
		desc.Size = UDim2.new(1, -6, 0, math.max(28, getfontsize(desc.Text, 10, uipallet.Font).Y + 4))
		desc.Position = UDim2.fromOffset(3, 0)
		desc.TextYAlignment = Enum.TextYAlignment.Top
		desc.TextWrapped = true

		function moduleapi:Clean(obj)
			if typeof(obj) == 'Instance' then
				table.insert(self.Connections, {Disconnect = function()
					if obj then pcall(function() obj:ClearAllChildren(); obj:Destroy() end) end
				end})
				return
			elseif type(obj) == 'function' then
				table.insert(self.Connections, {Disconnect = obj})
				return
			end
			table.insert(self.Connections, obj)
		end

		function moduleapi:Expand()
			if expandedSettings and expandedSettings ~= self and expandedSettings.SettingsWindow then
				expandedSettings.SettingsWindow.Closed = true
				expandedSettings.SettingsWindow:Apply()
			end
			self.SettingsWindow.Closed = false
			self.SettingsWindow.X = math.floor((row.AbsolutePosition.X + row.AbsoluteSize.X + 6) / scale.Scale)
			self.SettingsWindow.Y = math.floor(row.AbsolutePosition.Y / scale.Scale)
			self.SettingsWindow:Apply()
			expandedSettings = self
			bringToFront(self.SettingsWindow)
		end

		function moduleapi:SetBind(val)
			if type(val) == 'table' then
				self.Bind = val[1] or ''
			else
				self.Bind = val or ''
			end
		end

		function moduleapi:SetVisible(state)
			if self.Object then self.Object.Visible = state == true end
		end

		function moduleapi:SetExtraText(txt)
			self.ExtraText = txt
		end

		function moduleapi:Toggle(multiple)
			if mainapi.ThreadFix then setthreadidentity(8) end
			self.Enabled = not self.Enabled
			row.BackgroundColor3 = self.Enabled and uipallet.Enabled or uipallet.Main
			settingsStrip.BackgroundColor3 = self.Enabled and uipallet.Enabled or uipallet.Main
			text.TextColor3 = self.Enabled and uipallet.DarkText or uipallet.Text
			settingsStrip.TextColor3 = self.Enabled and uipallet.DarkText or uipallet.Enabled
			if not self.Enabled then
				for _, v in ipairs(self.Connections) do if type(v) == 'table' and v.Disconnect then safeCall(v.Disconnect, v) elseif typeof(v) == 'RBXScriptConnection' then safeCall(function() v:Disconnect() end) elseif type(v) == 'function' then safeCall(v) end end
				table.clear(self.Connections)
			end
			if not multiple then mainapi:UpdateTextGUI() end
			safeCall(self.Function, self.Enabled)
		end

		for compName, compFunc in pairs(components) do
			moduleapi['Create'..compName] = function(_, optionsettings)
				local ok, res = pcall(compFunc, optionsettings or {}, moduleapi.SettingsList, moduleapi)
				if ok then return res end
				warn('[Wurst UI] option failed for '..name..' / '..compName..': '..tostring(res))
				return createOptionBase(compName, optionsettings or {}, moduleapi.SettingsList, moduleapi)
			end
		end

		moduleapi.CreateTextBox = moduleapi.CreateTextbox or function(_, optionsettings)
			return components.Textbox(optionsettings or {}, moduleapi.SettingsList, moduleapi)
		end
		moduleapi.CreateColorSlider = moduleapi.CreateColorSlider or function(_, optionsettings)
			return components.ColorSlider(optionsettings or {}, moduleapi.SettingsList, moduleapi)
		end
		moduleapi.CreateDropdown = moduleapi.CreateDropdown or function(_, optionsettings)
			return components.Dropdown(optionsettings or {}, moduleapi.SettingsList, moduleapi)
		end
		moduleapi.CreateSlider = moduleapi.CreateSlider or function(_, optionsettings)
			return components.Slider(optionsettings or {}, moduleapi.SettingsList, moduleapi)
		end
		moduleapi.CreateToggle = moduleapi.CreateToggle or function(_, optionsettings)
			return components.Toggle(optionsettings or {}, moduleapi.SettingsList, moduleapi)
		end

		setmetatable(moduleapi, {
			__index = function(_, ind)
				local comp = tostring(ind):match('^Create(.+)$')
				if comp then
					return function(self, optionsettings)
						return safeCreateOption(comp, self or moduleapi, optionsettings)
					end
				end
				return function() return moduleapi end
			end
		})

		row.MouseButton1Click:Connect(function()
			moduleapi:Toggle()
		end)
		row.MouseButton2Click:Connect(function()
			moduleapi:Expand()
		end)
		settingsStrip.MouseButton1Click:Connect(function()
			moduleapi:Expand()
		end)
		if moduleapi.Tooltip then connectTooltip(row, moduleapi.Tooltip) end

		self.Modules[name] = moduleapi
		mainapi.Modules[key] = moduleapi
		if not mainapi.Modules[name] then mainapi.Modules[name] = moduleapi end
		mainapi.ModuleKeys[key] = key
		table.insert(mainapi.ModuleList, moduleapi)

		local rows = {}
		for _, module in pairs(self.Modules) do table.insert(rows, module) end
		table.sort(rows, function(a, b) return a.Name:lower() < b.Name:lower() end)
		for i, module in ipairs(rows) do
			module.Object.LayoutOrder = i
		end

		moduleapi.Object = row
		ensureModuleApi(moduleapi)
		window:Apply()
		return moduleapi
	end

	rawset(self.Categories, canonical, categoryapi)
	rawset(self.Categories, original, categoryapi)
	for alias, target in pairs(CATEGORY_ALIASES) do
		if target == canonical then rawset(self.Categories, alias, categoryapi) end
	end
	table.insert(self.CategoryOrder, categoryapi)
	return categoryapi
end

