end
radarWindow:Apply()

mainapi:Clean(clickgui.MouseButton1Click:Connect(function()
	closePopup()
end))

mainapi:Clean(gui:GetPropertyChangedSignal('AbsoluteSize'):Connect(function()
	updateAutoScale()
	for _, win in pairs(mainapi.Windows) do win:Apply() end
end))

mainapi:Clean(scale:GetPropertyChangedSignal('Scale'):Connect(function()
	scaledgui.Size = UDim2.fromScale(1 / scale.Scale, 1 / scale.Scale)
	for _, win in pairs(mainapi.Windows) do win:Apply() end
end))

mainapi:Clean(clickgui:GetPropertyChangedSignal('Visible'):Connect(function()
	updateWindowVisibility()
	if clickgui.Visible and inputService.MouseEnabled then
		repeat
			cursor.Visible = not inputService.MouseIconEnabled
			if cursor.Visible then
				local mouseLocation = inputService:GetMouseLocation()
				cursor.Position = UDim2.fromOffset(mouseLocation.X - 31, mouseLocation.Y - 32)
			end
			updateTooltipPosition()
			task.wait()
		until mainapi.Loaded == nil or not clickgui.Visible
		cursor.Visible = false
	end
end))

mainapi:Clean(inputService.InputBegan:Connect(function(inputObj)
	if not inputService:GetFocusedTextBox() and inputObj.KeyCode ~= Enum.KeyCode.Unknown then
		if mainapi.Binding then
			mainapi.Binding:SetBind(mainapi.Binding.Bind == inputObj.KeyCode.Name and '' or inputObj.KeyCode.Name, true)
			mainapi.Binding = nil
			return
		end

		if inputObj.KeyCode == mainapi.Keybind then
			if mainapi.ThreadFix then setthreadidentity(8) end
			clickgui.Visible = not clickgui.Visible
			updateWindowVisibility()
		end

		local toggled = false
		for _, moduleapi in ipairs(mainapi.ModuleList) do
			if moduleapi.Bind == inputObj.KeyCode.Name then
				toggled = true
				if mainapi.ToggleNotifications.Enabled then
					mainapi:CreateNotification('Module Toggled', moduleapi.Name..' toggled')
				end
				moduleapi:Toggle(true)
			end
		end
		if toggled then mainapi:UpdateTextGUI() end

		for _, v in pairs(mainapi.Profiles) do
			if v.Bind == inputObj.KeyCode.Name and v.Name ~= mainapi.Profile then
				mainapi:Save(v.Name)
				mainapi:Load(true)
				break
			end
		end
	end
end))

runService.RenderStepped:Connect(function()
	updateTooltipPosition()
	if radarWindow then
		radarWindow.Frame.Visible = (mainapi.Settings.Radar ~= false) and windowShouldShow(radarWindow)
	end
end)

task.defer(function()
	updateAutoScale()
	updateWindowVisibility()
	mainapi:UpdateTextGUI()
end)

mainapi.Loaded = true
if shared then
	shared.vape = mainapi
elseif getgenv then
	getgenv().vape = mainapi
end

return mainapi
